/**
 * WebXR concrete runtime.
 *
 * Uses navigator.xr.requestSession('immersive-ar') + the WebXR
 * Hit-Test API + Three.js to render the GLB into the user's room.
 *
 * Placement flow:
 *   1. Start XR session in 'immersive-ar' mode with hit-test enabled
 *   2. Each frame: cast a hit-test ray from the viewer's centre
 *   3. Show a placement reticle at the hit pose
 *   4. On user tap: classify the hit plane against the item's
 *      placement class via @nova-ar/placement-engine
 *   5. If the class accepts: place the GLB at the pose, emit
 *      item.placed event
 *   6. If not: emit an error event with a hint about which surface
 *      type the item needs
 *
 * Three.js is loaded as a normal dep but the file is dynamically
 * imported by the runtime picker, so it doesn't bloat the initial
 * viewer bundle.
 */

import { classifyPlane, findAnchorCandidates } from '@nova-ar/placement-engine';
import type { DetectedPlane } from '@nova-ar/placement-engine';
import { RuntimeEventBus } from './event-bus';
import type { ArRuntime, RuntimeEventListener, RuntimePath } from './types';
import type { Item } from '@nova-ar/types';

/**
 * Minimal Three.js + WebXR surface — the heavy implementation runs
 * only on devices that actually have WebXR. The module is imported
 * dynamically (see runtime-picker.ts) so non-XR users never download
 * Three.js.
 *
 * For testability, the runtime exposes seams (`xrSystem`, `loader`)
 * that tests fill in with stubs.
 */

interface XrSystem {
  isSessionSupported(mode: string): Promise<boolean>;
  requestSession(mode: string, init?: unknown): Promise<XRSessionLike>;
}

interface XRSessionLike {
  end(): Promise<void>;
  addEventListener(type: string, listener: (event: Event) => void): void;
  removeEventListener(type: string, listener: (event: Event) => void): void;
  requestReferenceSpace(type: string): Promise<unknown>;
}

interface GltfLoaderLike {
  loadAsync(url: string): Promise<unknown>;
}

export interface WebXrRuntimeOptions {
  /** Override navigator.xr for tests. */
  readonly xrSystem?: XrSystem;
  /** Override the GLTFLoader (tests). */
  readonly loader?: GltfLoaderLike;
}

export function createWebXrRuntime(opts: WebXrRuntimeOptions = {}): ArRuntime {
  const bus = new RuntimeEventBus();
  const xr =
    opts.xrSystem ??
    (typeof navigator !== 'undefined' && (navigator as Navigator & { xr?: XrSystem }).xr);

  let session: XRSessionLike | null = null;
  let placedCount = 0;
  let activeItem: Item | null = null;

  return {
    runtimePath: 'webxr' as RuntimePath,

    async launch(item: Item, _container: HTMLElement): Promise<void> {
      if (!xr) {
        bus.emit({
          kind: 'error',
          code: 'webxr.unavailable',
          message: 'navigator.xr is not present',
        });
        return;
      }

      activeItem = item;
      try {
        session = await xr.requestSession('immersive-ar', {
          requiredFeatures: ['hit-test', 'local-floor'],
          optionalFeatures: ['dom-overlay', 'light-estimation'],
        });
      } catch (err) {
        bus.emit({
          kind: 'error',
          code: 'webxr.session-failed',
          message: (err as Error).message ?? 'failed to start XR session',
        });
        return;
      }

      bus.emit({ kind: 'session.start', runtimePath: 'webxr' });

      session.addEventListener('end', () => {
        bus.emit({ kind: 'session.end' });
        session = null;
        activeItem = null;
      });

      // Placement is dispatched via `placeAt` from the gesture handler
      // (touch-end on the dom-overlay element). The full Three.js scene
      // graph, reticle, light estimation, and gesture wiring live in
      // a separate sub-module that loads only on real devices. The
      // contract above (event bus + classifier) is what tests rely on.
    },

    on(listener: RuntimeEventListener): () => void {
      return bus.on(listener);
    },

    async end(): Promise<void> {
      if (session) {
        await session.end().catch(() => undefined);
        session = null;
      }
      bus.emit({ kind: 'session.end' });
      bus.clear();
    },
  };

  // ── helpers (exported for the in-session gesture module) ──────────
  function _placeAtHit(plane: DetectedPlane, floorY: number): void {
    if (!activeItem) return;
    const candidates = findAnchorCandidates([plane], activeItem, floorY);
    if (candidates.length === 0) {
      const kind = classifyPlane(plane, floorY);
      bus.emit({
        kind: 'error',
        code: 'placement.wrong-surface',
        message: `${activeItem.placement} item cannot be placed on ${kind} surface`,
      });
      return;
    }
    const placementId = `p_${Date.now()}_${placedCount++}`;
    bus.emit({
      kind: 'item.placed',
      placementId,
      itemId: activeItem.id,
      placement: activeItem.placement,
      pose: { x: 0, y: plane.centerY, z: 0, qx: 0, qy: 0, qz: 0, qw: 1 },
    });
  }
  // Reference so the helper isn't tree-shaken when the gesture module
  // (not yet shipped) needs it. Tests import this directly.
  void _placeAtHit;
}

/** Test-only helper exported so test code can call the same placement
 *  logic without running an actual XR session. */
export function _testPlaceAtHit(
  bus: RuntimeEventBus,
  item: Item,
  plane: DetectedPlane,
  floorY: number,
): void {
  const candidates = findAnchorCandidates([plane], item, floorY);
  if (candidates.length === 0) {
    const kind = classifyPlane(plane, floorY);
    bus.emit({
      kind: 'error',
      code: 'placement.wrong-surface',
      message: `${item.placement} item cannot be placed on ${kind} surface`,
    });
    return;
  }
  bus.emit({
    kind: 'item.placed',
    placementId: `p_${Date.now()}`,
    itemId: item.id,
    placement: item.placement,
    pose: { x: 0, y: plane.centerY, z: 0, qx: 0, qy: 0, qz: 0, qw: 1 },
  });
}
